INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (155, "人助け、応援", "A", 100101, "ヒヨリ", "獣人族", 2, "人助けが大好き！　前向き格闘娘", 16, "トゥインクルウィッシュ", "東山奈央", 0, 44, "こんにちは！　ヒヨリでっす！\n困っている人がいたら助けにいくよ！\nよかったら一緒に来ない？", 8, 27);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (158, "料理、人間観察", "O", 100201, "ユイ", "ヒューマン", 2, "戦闘のサポートが得意な、心優しい少女", 17, "トゥインクルウィッシュ", "種田梨沙", 0, 47, "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！", 4, 5);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (163, "読書、乗馬、お茶", "B", 100301, "レイ", "魔族", 2, "クールで何事にも真っ直ぐな剣士", 18, "トゥインクルウィッシュ", "早見沙織", 0, 46, "キミと会ったのもきっと何かの縁だ\n一緒に塔の頂上を目指す仲間として\n頑張っていこう。よろしく頼む", 1, 12);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (128, "いたずら、探検", "O", 100401, "ミソギ", "ヒューマン", 5, "探検好きのイタズラっ子", 9, "リトルリリカル", "諸星すみれ", 0, 27, "イタズラなら任せて！\nにいちゃん、引っかからないように気を付けなよー♪", 8, 10);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (146, "ヒーローごっこ", "O", 100501, "マツリ", "獣人族", 8, "ヒーローに憧れる騎士見習いの少女", 12, "王宮騎士団（NIGHTMARE）", "下田麻美", 0, 40, "？？？", 11, 25);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (150, "サックス", "O", 100601, "アカリ", "魔族", 7, "甘え上手なみんなの人気者", 13, "悪魔偽王国軍（ディアボロス）", "浅倉杏美", 0, 42, "アカリ、まだわからないことが多くて…\nだからこれから\nいろいろ教えてくださいね、お兄ちゃん！", 11, 22);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (130, "プリンを食べること", "B", 100701, "ミヤコ", "魔族", 7, "プリン大好きゴースト娘", 14, "悪魔偽王国軍（ディアボロス）", "雨宮天", 0, 32, "難しいことはわからないの～\nただ毎日プリンを食べられるなら、\n幽霊のままでいいの～", 1, 23);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (150, "鏡で自分を見ること", "AB", 100801, "ユキ", "エルフ", 15, "ボクは誰よりも美しい", 14, "ヴァイスフリューゲル　ランドソル支部", "大空直美", 0, 40, "ボクって本当に美しいなあ…\n可愛くて美しいなんて本当に罪だと思うけど\n生まれもったものだから仕方ないんだ♪", 10, 10);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (159, "小説執筆", "A", 100901, "アンナ", "魔族", 13, "前世を信じる中二病患者、「疾風の冥姫」", 17, "トワイライトキャラバン", "髙野麻美", 0, 45, "いいか、絶対に私を真名で呼ぶなよ？\n常に「機関」の眼や耳の存在を疑え\nそれが、生きのびるための術だ…！", 7, 5);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (155, "空想、ぬいぐるみ集め", "O", 101001, "マホ", "獣人族", 10, "マホマホ王国のプリンセス", 16, "自警団（カォン）", "内田真礼", 0, 42, "マホマホ王国のお姫はんの、マホ姫どす！\nけったいな顔してどないしはったん？\nマホマホ王国はずーっと遠くの国なんどす？", 9, 22);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (156, "お裁縫", "A", 101101, "リノ", "ヒューマン", 3, "人懐っこくてマシンガントークな妹系少女", 15, "ラビリンス", "阿澄佳奈", 0, 44, "覚えていないと思うんですけど…\n私は妹なんですよ！\nだからお兄ちゃんって呼んでいいですか？", 8, 25);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (156, "妹と遊ぶこと、二度寝、昼寝、早寝", "A", 101201, "ハツネ", "エルフ", 6, "みんなのために超能力を使う眠り姫", 17, "フォレスティエ", "大橋彩香", 0, 46, "私はハツネ！　困っている人の味方だよ！\n困った時は、いつでも言ってね♪\n私のちょ…ま、魔法で助けてあげるから！", 12, 24);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (166, "読書、魔法", "O", 101301, "ナナカ", "魔族", 13, "オタク全開な魔法少女", 18, "トワイライトキャラバン", "佳村はるか", 0, 55, "", 8, 21);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (152, "読書、推理", "AB", 101401, "カスミ", "獣人族", 10, "頭脳明晰な美少女名探偵", 15, "自警団（カォン）", "水瀬いのり", 0, 41, "test", 11, 3);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (165, "絵本作り", "O", 101501, "ミサト", "エルフ", 6, "母性溢れる優しいみんなの「ミサト先生」", 21, "フォレスティエ", "國府田マリ子", 0, 54, "test", 9, 5);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (167, "ファッション", "O", 101601, "スズナ", "魔族", 14, "天真爛漫で人気者のカリスマモデル", 17, "ルーセント学院", "上坂すみれ", 0, 48, "ヒデサイ、ちょっす～！　うち、漢字と計算は\nちょっち…てか、おに苦手なんだ～\nでもでも、ファッションだったら任せて～！", 4, 10);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (158, "踊り、空手", "A", 101701, "カオリ", "獣人族", 10, "いつでも「なんくるないさ～」な天然娘", 17, "自警団（カォン）", "高森奈津美", 0, 53, "ハイターイ！　歌って踊って、\n最高に盛り上がるさ～！\nやさやさ、キミも一緒に踊るさ～！", 7, 7);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (162, "恋愛小説、恋愛舞台、恋愛漫画の鑑賞", "B", 101801, "イオ", "魔族", 14, "多くの男性を魅了する無垢な女教師", 23, "ルーセント学院", "伊藤静", 0, 52, "いつも助けてくれてありがとう\n私のほうが年上なのに\n頼ってばかりでごめんなさい～", 8, 14);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (117, "かわいいもの集め", "O", 102001, "ミミ", "獣人族", 5, "お歌もにんじんも、ウサギさんも大好き♪", 10, "リトルリリカル", "日高里菜", 0, 21, "ぴょんぴょん、うさぎさんになりたいな～♪　\nミミ、うさぎさんになれたら、\n最初におにいちゃんに見せてあげるね！", 4, 3);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (150, "観劇、おままごと", "B", 102101, "クルミ", "ヒューマン", 9, "泣き虫で臆病な守ってあげたい女の子", 12, "サレンディア救護院", "植田佳奈", 0, 40, "あの、えっと…私、く、クルミですぅ…\nふ、ふぇぇぇ…ど、どうしようぅ…\nは、恥かしくて…ご、ごめんなさいぃぃ！", 6, 9);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (150, "ゲーム全般", "O", 102201, "ヨリ", "魔族", 7, "人見知りであまのじゃくな女の子", 13, "悪魔偽王国軍（ディアボロス）", "原紗友里", 0, 40, "え、えっと…こ、こういうときって、\nどういうことを言えばいいんだっけ…\nうう、どうしてちゃんと喋れないの…", 11, 22);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (148, "屋内でできる遊び", "B", 102301, "アヤネ", "ヒューマン", 9, "ぷうきちといつも一緒！", 14, "サレンディア救護院", "芹澤優", 0, 38, "この子はね、ぷうきちって言うんだ\n武器なんだけど、しゃべるんだよ♪\n大事な大事な、私の友達なんだぁ～！", 5, 10);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (154, "ご奉仕", "O", 102501, "スズメ", "ヒューマン", 9, "お嬢さまのためにがんばるドジっ娘メイド", 15, "サレンディア救護院", "悠木碧", 0, 43, "うぅ…ごめんなさい～…\nまたキッチンを爆発させてしまいました～\nこれじゃあメイド失格です…", 12, 12);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (144, "あんパン", "B", 102601, "リン", "獣人族", 11, "遊びと睡眠が何より大事なぐうたら娘", 17, "牧場（エリザベスパーク）", "小岩井ことり", 0, 42, "test", 1, 1);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (154, "実験、裁縫、料理", "B", 102701, "エリコ", "魔族", 13, "運命の相手に一途すぎる乙女", 16, "トワイライトキャラバン", "橋本ちなみ", 0, 43, "『壊し屋』の二つ名を持つ私…\nですが、怖がる必要はありませんわ\nあなた様は大切な運命の人ですから…", 7, 30);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (156, "経営、お茶会", "A", 102801, "サレン", "エルフ", 9, "救護院を経営する優しい庶民派お嬢様", 17, "サレンディア救護院", "堀江由衣", 0, 43, "貧乏性？　いいえ、\n「もったいない」の精神で\n日々を過ごしてるだけよ！", 10, 4);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (157, "舞台鑑賞、ダンス", "B", 102901, "ノゾミ", "ヒューマン", 4, "歌って踊れる大人気アイドル", 17, "カルミナ", "日笠陽子", 0, 40, "いつか世界中の人達をファンにしてみせる！\nトップアイドルになるその日まで、\n応援よろしくね♪", 1, 24);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (163, "忍法開発", "O", 103001, "ニノン", "ヒューマン", 15, "トーゴクの神秘、オシエテクダサイ！", 16, "ヴァイスフリューゲル　ランドソル支部", "佐藤聡美", 0, 51, "スシ、ゲイシャ、テンプラ…\nはふぅ～！\nトーゴクの文化はステキデスね～！", 8, 31);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (157, "占い", "AB", 103101, "シノブ", "魔族", 7, "占いが得意な霊能少女", 18, "悪魔偽王国軍（ディアボロス）", "大坪由佳", 0, 42, "私、小さい頃から人には見えないものが\n見えていたんです。今もあなたの後ろに\n一人、二人、三人…賑やかですね", 12, 22);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (157, "慈善事業", "AB", 103201, "アキノ", "ヒューマン", 12, "一人前の商人を目指すパワフルお嬢様", 18, "メルクリウス財団", "松嵜麗", 0, 45, "この私とともにいる限り、\nお金に不自由はさせませんわ！", 3, 12);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (142, "漫才", "B", 103301, "マヒル", "ヒューマン", 11, "みんなを笑顔にするお笑い牧場主", 20, "牧場（エリザベスパーク）", "新田恵海", 0, 35, "オラはどんな時でもみんなに笑顔を届ける\n最高の芸人目指してる！\n一緒に頑張るべ！", 3, 3);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (164, "ウインドーショッピング", "A", 103401, "ユカリ", "エルフ", 12, "純情でほっとけない大人の女性", 22, "メルクリウス財団", "今井麻美", 0, 55, "キミには情けないところばかり\n見られているけど、こんなところ、\nキミ以外には見せないんだからね？", 3, 16);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (118, "お勉強", "A", 103601, "キョウカ", "エルフ", 5, "礼儀正しくしっかり者のちびっ子優等生", 8, "リトルリリカル", "小倉唯", 0, 21, "test", 2, 2);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (149, "剣術、年長者をからかう", "A", 103701, "トモ", "ヒューマン", 8, "義理堅くてからかい好きな剣術少女", 13, "王宮騎士団（NIGHTMARE）", "茅原実里", 0, 43, "test", 8, 11);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (153, "読書、お散歩", "A", 103801, "シオリ", "獣人族", 11, "読書が趣味の病弱少女", 14, "牧場（エリザベスパーク）", "小清水亜美", 0, 40, "ゴホッ、ゴホッ…か、身体は弱いけど、\nせめて気持ちだけでも前向きに…！\nあっ、でもダメ…立ちくらみが…", 11, 3);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (158, "友達作りのイメトレ", "AB", 104001, "アオイ", "エルフ", 6, "「友達」に憧れる、エルフの森の女の子", 13, "フォレスティエ", "花澤香菜", 0, 44, "友達ができるその日まで…\nBB団で\nトレーニングですっ！", 6, 6);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (163, "各種楽器", "O", 104201, "チカ", "ヒューマン", 4, "人々を守るために歌う、唱喚士の少女", 17, "カルミナ", "福原綾香", 0, 46, "私は人々の平和を守るため、唱喚術を使って\n戦います。…最近は、ア、アイドルとしても\n活動してますが、そちらはまだ不慣れで…", 6, 3);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (168, "お菓子作り", "O", 104301, "マコト", "獣人族", 10, "男勝りで情に厚いワイルド娘", 17, "自警団（カォン）", "小松未可子", 0, 54, "腹へってたら言えよな\n簡単でよければ\nすっげー旨いもん食わせてやるよ！", 8, 9);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (172, "世界征服", "A", 104401, "イリヤ", "魔族", 7, "かつては夜を支配した最強の吸血鬼", "??", "悪魔偽王国軍（ディアボロス）", "丹下桜", 0, 50, "test", 5, 5);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (157, "小説を読むこと", "AB", 104501, "クウカ", "ヒューマン", 15, "妄想大好き！　ほんとは照れ屋な女の子", 18, "ヴァイスフリューゲル　ランドソル支部", "長妻樹里", 0, 49, "あなたのことを考えていました\n…逆らえないクウカをああして、こうして\nぐふ、ぐふふふ…", 11, 19);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (158, "猫とたわむれること", "AB", 104601, "タマキ", "獣人族", 12, "弱きを助け強きをくじく猫娘", 19, "メルクリウス財団", "沼倉愛美", 0, 48, "お金もうけの話なら、ぜひともあたしに\n持ってくるにゃ！　稼げるなら１ルピだって\n見逃さないのが、あたしの信条にゃ～♪", 3, 1);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (171, "格闘技、湯浴み", "A", 104701, "ジュン", "ヒューマン", 8, "素顔を見せない冷静沈着な女性騎士", 25, "王宮騎士団（NIGHTMARE）", "川澄綾子", 0, 50, "？？？", 10, 25);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (163, "傭兵などのアルバイト", "O", 104801, "ミフユ", "ヒューマン", 12, "仕事も私事も効率優先な傭兵少女", 20, "メルクリウス財団", "田所あずさ", 0, 49, "私がキミの師匠になってあげる！\nもちろんタダとはいかないわ\n時給はしっかりもらうから", 11, 11);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (168, "家事全般", "O", 104901, "シズル", "ヒューマン", 3, "お姉ちゃんがお世話してあげるからねっ！", 18, "ラビリンス", "生天目仁美", 0, 54, "身の回りのお世話はお姉ちゃんがやってあげるね！\nお料理も、お洗濯も、お掃除も\nお風呂で背中も流してあげちゃうぞっ！", 10, 24);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (120, "ファッション誌鑑賞、コスメ集め", "A", 105001, "ミサキ", "魔族", 14, "ちょっとおませな恋に恋する女の子", 11, "ルーセント学院", "久野美咲", 0, 22, "アタシのこと呼んだ？\nレディの魅力で夢中にさせてあげるわね！", 1, 3);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (166, "研究、実験", "A", 105101, "ミツキ", "ヒューマン", 13, "実験が趣味の危険な科学者", 27, "トワイライトキャラバン", "三石琴乃", 0, 53, "私は科学者だけど、\n医者の真似事もしてるの\n病気になったら診てあげるわ", 3, 7);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (150, "毛繕い、お喋り", "A", 105201, "リマ", "獣人族", 11, "乙女チックなもふもふアニマル", 17, "牧場（エリザベスパーク）", "徳井青空", 0, 100, "私、ごく普通の、どこにでもいる女の子よ！\nみ、見た目以外はね…", 3, 14);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (140, "お菓子屋通い", "A", 105301, "モニカ", "ヒューマン", 15, "見た目も中身もお子ちゃまな異国の軍人", 17, "ヴァイスフリューゲル　ランドソル支部", "辻あゆみ", 0, 33, "「白き翼」こと、ヴァイスフリューゲル…\nその名に恥じぬよう、天高く舞い、\n華麗に敵を倒してみせる！", 7, 28);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (153, "裁縫", "AB", 105401, "ツムギ", "ヒューマン", 4, "ファッション大好きなキュートガール", 14, "カルミナ", "木戸衣吹", 0, 45, "test", 9, 7);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (155, "観察", "O", 105501, "アユミ", "エルフ", 15, "どこまでも一途に慕う、純情乙女", 16, "ヴァイスフリューゲル　ランドソル支部", "大関英里", 0, 43, "test", 4, 7);
