INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (156, "冒険、おしゃべり", "O", 105701, "ジータ", "ヒューマン", "", "空への冒険を夢見る騎空士の少女", 17, "？？？", "金元寿子", 0, 45, "私ね、一人前の騎空士になりたいんだ\nいつか父さんみたいな騎空士になって、\n空の果てまで旅する。それが私の夢だよ！", 3, 10);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (156, "食べ歩き、料理", "O", 105801, "ペコリーヌ", "ヒューマン", 1, "いつも元気な腹ペコ少女", 17, "美食殿", "M・A・O", 0, 46, "あ、あの…何か食べ物持っていませんか？\nもう、お腹ペコペコで…", 3, 31);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (140, "瞑想、動植物の飼育", "B", 105901, "コッコロ", "エルフ", 1, "主を慕う、小さなガイド役", 11, "美食殿", "伊藤美来", 0, 35, "主さまのガイド役を仰せつかりました\nわたくし、主さまに満足していただけるよう\n誠心誠意尽くさせていただきます", 5, 11);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (152, "猫と遊ぶ", "A", 106001, "キャル", "獣人族", 1, "行き倒れの謎のネコミミ魔法使い", 14, "美食殿", "立花理香", 0, 39, "なに、モタモタしてんのよ\n仕方ないから、あたしが手伝ってあげるわ\nいい？　感謝しなさいよね！", 9, 2);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (148, "冒険、思い出話", "O", 106101, "ムイミ", "ヒューマン", "", "さまよえる謎の少女", 16, "？？？", "潘めぐみ", 0, 40, "いいんだ、アタシは……独りでも。大丈夫だから、もう慣れたからさぁ", 8, 11);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (155, "キレイな葉っぱを集めること", "O", 106301, "アリサ", "エルフ", "", "森番を目指すエルフの少女", 15, "？？？", "優木かな", 0, 42, "", 6, 17);
