INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (168, "絵画、読書", "O", 106701, "ホマレ", "ドラゴン族", 17, "妖しい微笑で全てを見透かす臥竜の頭領", 25, "ドラゴンズネスト", "大西沙織", 0, "???", "", 4, 17);
