INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (165, "強敵との闘争", "O", 107101, "クリスティーナ", "ヒューマン", 8, "傍若無人な王宮騎士団副団長", 27, "王宮騎士団（NIGHTMARE）", "たかはし智秋", 0, "??", "", 2, 7);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (156, "食べ歩き、料理", "O", 107501, "ペコリーヌ（サマー）", "ヒューマン", 1, "いつも元気な腹ペコ少女", 17, "美食殿", "M・A・O", 0, 46, "あ、あの…何か食べ物持っていませんか？\nもう、お腹ペコペコで…", 3, 31);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (140, "瞑想、動植物の飼育", "B", 107601, "コッコロ（サマー）", "エルフ", 1, "主を慕う、小さなガイド役", 11, "美食殿", "伊藤美来", 0, 35, "主さまのガイド役を仰せつかりました\nわたくし、主さまに満足していただけるよう\n誠心誠意尽くさせていただきます", 5, 11);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (154, "ご奉仕", "O", 107701, "スズメ（サマー）", "ヒューマン", 9, "お嬢さまのためにがんばるドジっ娘メイド", 15, "サレンディア救護院", "悠木碧", 0, 43, "うぅ…ごめんなさい～…\nまたキッチンを爆発させてしまいました～\nこれじゃあメイド失格です…", 12, 12);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (152, "猫と遊ぶ", "A", 107801, "キャル（サマー）", "獣人族", 1, "行き倒れの謎のネコミミ魔法使い", 14, "美食殿", "立花理香", 0, 39, "なに、モタモタしてんのよ\n仕方ないから、あたしが手伝ってあげるわ\nいい？　感謝しなさいよね！", 9, 2);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (158, "猫とたわむれること", "AB", 107901, "タマキ（サマー）", "獣人族", 12, "弱きを助け強きをくじく猫娘", 19, "メルクリウス財団", "沼倉愛美", 0, 48, "お金もうけの話なら、ぜひともあたしに\n持ってくるにゃ！　稼げるなら１ルピだって\n見逃さないのが、あたしの信条にゃ～♪", 3, 1);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (163, "傭兵などのアルバイト", "O", 108001, "ミフユ（サマー）", "ヒューマン", 12, "仕事も私事も効率優先な傭兵少女", 20, "メルクリウス財団", "田所あずさ", 0, 49, "私がキミの師匠になってあげる！\nもちろんタダとはいかないわ\n時給はしっかりもらうから", 11, 11);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (157, "占い", "AB", 108101, "シノブ（ハロウィン）", "魔族", 7, "占いが得意な霊能少女", 18, "悪魔偽王国軍（ディアボロス）", "大坪由佳", 0, 42, "私、小さい頃から人には見えないものが\n見えていたんです。今もあなたの後ろに\n一人、二人、三人…賑やかですね", 12, 22);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (130, "プリンを食べること", "B", 108201, "ミヤコ（ハロウィン）", "魔族", 7, "プリン大好きゴースト娘", 14, "悪魔偽王国軍（ディアボロス）", "雨宮天", 0, 32, "難しいことはわからないの～\nただ毎日プリンを食べられるなら、\n幽霊のままでいいの～", 1, 23);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (120, "ファッション誌鑑賞、コスメ集め", "A", 108301, "ミサキ（ハロウィン）", "魔族", 14, "ちょっとおませな恋に恋する女の子", 11, "ルーセント学院", "久野美咲", 0, 22, "アタシのこと呼んだ？\nレディの魅力で夢中にさせてあげるわね！", 1, 3);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (163, "各種楽器", "O", 108401, "チカ（クリスマス）", "ヒューマン", 4, "人々を守るために歌う、唱喚士の少女", 17, "カルミナ", "福原綾香", 0, 46, "私は人々の平和を守るため、唱喚術を使って\n戦います。…最近は、ア、アイドルとしても\n活動してますが、そちらはまだ不慣れで…", 6, 3);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (150, "観劇、おままごと", "B", 108501, "クルミ（クリスマス）", "ヒューマン", 9, "泣き虫で臆病な守ってあげたい女の子", 12, "サレンディア救護院", "植田佳奈", 0, 40, "あの、えっと…私、く、クルミですぅ…\nふ、ふぇぇぇ…ど、どうしようぅ…\nは、恥かしくて…ご、ごめんなさいぃぃ！", 6, 9);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (148, "屋内でできる遊び", "B", 108601, "アヤネ（クリスマス）", "ヒューマン", 9, "ぷうきちといつも一緒！", 14, "サレンディア救護院", "芹澤優", 0, 38, "この子はね、ぷうきちって言うんだ\n武器なんだけど、しゃべるんだよ♪\n大事な大事な、私の友達なんだぁ～！", 5, 10);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (155, "人助け、応援", "A", 108701, "ヒヨリ（ニューイヤー）", "獣人族", 2, "人助けが大好き！　前向き格闘娘", 16, "トゥインクルウィッシュ", "東山奈央", 0, 44, "こんにちは！　ヒヨリでっす！\n困っている人がいたら助けにいくよ！\nよかったら一緒に来ない？", 8, 27);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (158, "料理、人間観察", "O", 108801, "ユイ（ニューイヤー）", "ヒューマン", 2, "戦闘のサポートが得意な、心優しい少女", 17, "トゥインクルウィッシュ", "種田梨沙", 0, 47, "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！", 4, 5);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (163, "読書、乗馬、お茶", "B", 108901, "レイ（ニューイヤー）", "魔族", 2, "クールで何事にも真っ直ぐな剣士", 18, "トゥインクルウィッシュ", "早見沙織", 0, 46, "キミと会ったのもきっと何かの縁だ\n一緒に塔の頂上を目指す仲間として\n頑張っていこう。よろしく頼む", 1, 12);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (154, "実験、裁縫、料理", "B", 109001, "エリコ（バレンタイン）", "魔族", 13, "運命の相手に一途すぎる乙女", 16, "トワイライトキャラバン", "橋本ちなみ", 0, 43, "『壊し屋』の二つ名を持つ私…\nですが、怖がる必要はありませんわ\nあなた様は大切な運命の人ですから…", 7, 30);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (168, "家事全般", "O", 109101, "シズル（バレンタイン）", "ヒューマン", 3, "お姉ちゃんがお世話してあげるからねっ！", 18, "ラビリンス", "生天目仁美", 0, 54, "身の回りのお世話はお姉ちゃんがやってあげるね！\nお料理も、お洗濯も、お掃除も\nお風呂で背中も流してあげちゃうぞっ！", 10, 24);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (156, "読書", "AB", 109201, "アン", "ヒューマン", "", "英霊と契約を結んだマナリアの天才王女", 17, "？？？", "日笠陽子", 0, 55, "私はアン！一応、マナリア王国の\n第一王女だけど…あまりかしこまらないで、\n気軽に仲良くしてくれたら嬉しいな！", 12, 1);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (144, "食べること、眠ること", "O", 109301, "ルゥ", "ヒューマン", "", "マナリア魔法学院の新入生", 16, "？？？", "こやまきみこ", 0, 45, "ルゥはルゥですぅ！マナリア魔法学院に\n通ってるですぅ。あなたもルゥの\nお友だちになってくれるですか？", 2, 4);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (167, "ピアノ", "B", 109401, "グレア", "半人半竜", "", "人を超越した力を有す心優しい竜姫", 17, "？？？", "福原綾香", 0, 67, "私はグレア。竜と人、両方の血を\n受け継いでいるの…\nえっと…よ、よろしくね", 11, 3);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (157, "小説を読むこと", "AB", 109501, "クウカ（オーエド）", "ヒューマン", 15, "妄想大好き！　ほんとは照れ屋な女の子", 18, "ヴァイスフリューゲル　ランドソル支部", "長妻樹里", 0, 49, "あなたのことを考えていました\n…逆らえないクウカをああして、こうして\nぐふ、ぐふふふ…", 11, 19);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (163, "忍法開発", "O", 109601, "ニノン（オーエド）", "ヒューマン", 15, "トーゴクの神秘、オシエテクダサイ！", 16, "ヴァイスフリューゲル　ランドソル支部", "佐藤聡美", 0, 51, "スシ、ゲイシャ、テンプラ…\nはふぅ～！\nトーゴクの文化はステキデスね～！", 8, 31);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (154, "演劇鑑賞、詩文", "?", 109701, "レム", "鬼族", "", "鬼がかりの万能妹メイド", 17, "？？？", "水瀬いのり", 0, "??", "", 2, 2);
