INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (155, "空想、ぬいぐるみ集め", "O", 110601, "マホ（サマー）", "獣人族", 10, "マホマホ王国のプリンセス", 16, "自警団（カォン）", "内田真礼", 0, 42, "マホマホ王国のお姫はんの、マホ姫どす！\nけったいな顔してどないしはったん？\nマホマホ王国はずーっと遠くの国なんどす？", 9, 22);
