INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (117, "かわいいもの集め", "O", 111301, "ミミ（ハロウィン）", "獣人族", 5, "お歌もにんじんも、ウサギさんも大好き♪", 10, "リトルリリカル", "日高里菜", 0, 21, "ぴょんぴょん、うさぎさんになりたいな～♪　\nミミ、うさぎさんになれたら、\n最初におにいちゃんに見せてあげるね！", 4, 3);
