INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (156, "食べ歩き、料理", "O", 111801, "ぺコリーヌ（ニューイヤー）", "ヒューマン", 1, "いつも元気な腹ペコ少女", 17, "美食殿", "M・A・O", 0, 46, "あ、あの…何か食べ物持っていませんか？\nもう、お腹ペコペコで…", 3, 31);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (140, "瞑想、動植物の飼育", "B", 111901, "コッコロ（ニューイヤー）", "エルフ", 1, "主を慕う、小さなガイド役", 11, "美食殿", "伊藤美来", 0, 35, "主さまのガイド役を仰せつかりました\nわたくし、主さまに満足していただけるよう\n誠心誠意尽くさせていただきます", 5, 11);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (152, "猫と遊ぶ", "A", 112001, "キャル（ニューイヤー）", "獣人族", 1, "行き倒れの謎のネコミミ魔法使い", 14, "美食殿", "立花理香", 0, 39, "なに、モタモタしてんのよ\n仕方ないから、あたしが手伝ってあげるわ\nいい？　感謝しなさいよね！", 9, 2);
