INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (142, "漫才", "B", 112801, "マヒル（レンジャー）", "ヒューマン", 11, "みんなを笑顔にするお笑い牧場主", 20, "牧場（エリザベスパーク）", "新田恵海", 0, 35, "オラはどんな時でもみんなに笑顔を届ける\n最高の芸人目指してる！\n一緒に頑張るべ！", 3, 3);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (156, "お裁縫", "A", 112901, "リノ（ワンダー）", "ヒューマン", 3, "人懐っこくてマシンガントークな妹系少女", 15, "ラビリンス", "阿澄佳奈", 0, 44, "覚えていないと思うんですけど…\n私は妹なんですよ！\nだからお兄ちゃんって呼んでいいですか？", 8, 25);
