INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (159, "小説執筆", "A", 113201, "アンナ（サマー）", "魔族", 13, "前世を信じる中二病患者、「疾風の冥姫」", 17, "トワイライトキャラバン", "髙野麻美", 0, 45, "いいか、絶対に私を真名で呼ぶなよ？\n常に「機関」の眼や耳の存在を疑え\nそれが、生きのびるための術だ…！", 7, 5);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (166, "読書、魔法", "O", 113301, "ナナカ（サマー）", "魔族", 13, "オタク全開な魔法少女", 18, "トワイライトキャラバン", "佳村はるか", 0, 55, "", 8, 21);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (156, "妹と遊ぶこと、二度寝、昼寝、早寝", "A", 113401, "ハツネ（サマー）", "エルフ", 6, "みんなのために超能力を使う眠り姫", 17, "フォレスティエ", "大橋彩香", 0, 46, "私はハツネ！　困っている人の味方だよ！\n困った時は、いつでも言ってね♪\n私のちょ…ま、魔法で助けてあげるから！", 12, 24);
