INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (150, "サックス", "O", 113701, "アカリ（エンジェル）", "魔族", 7, "甘え上手なみんなの人気者", 13, "悪魔偽王国軍（ディアボロス）", "浅倉杏美", 0, 42, "アカリ、まだわからないことが多くて…\nだからこれから\nいろいろ教えてくださいね、お兄ちゃん！", 11, 22);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (150, "ゲーム全般", "O", 113801, "ヨリ（エンジェル）", "魔族", 7, "人見知りであまのじゃくな女の子", 13, "悪魔偽王国軍（ディアボロス）", "原紗友里", 0, 40, "え、えっと…こ、こういうときって、\nどういうことを言えばいいんだっけ…\nうう、どうしてちゃんと喋れないの…", 11, 22);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (153, "裁縫", "AB", 113901, "ツムギ（ハロウィン）", "ヒューマン", 4, "ファッション大好きなキュートガール", 14, "カルミナ", "木戸衣吹", 0, 45, "", 9, 7);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (163, "読書、乗馬、お茶", "B", 114001, "レイ（ハロウィン）", "魔族", 2, "クールで何事にも真っ直ぐな剣士", 18, "トゥインクルウィッシュ", "早見沙織", 0, 46, "キミと会ったのもきっと何かの縁だ\n一緒に塔の頂上を目指す仲間として\n頑張っていこう。よろしく頼む", 1, 12);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (146, "ヒーローごっこ", "O", 114101, "マツリ（ハロウィン）", "獣人族", 8, "ヒーローに憧れる騎士見習いの少女", 12, "王宮騎士団（NIGHTMARE）", "下田麻美", 0, 40, "", 11, 25);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (140, "お菓子屋通い", "A", 114201, "モニカ（マジカル）", "ヒューマン", 15, "見た目も中身もお子ちゃまな異国の軍人", 17, "ヴァイスフリューゲル　ランドソル支部", "辻あゆみ", 0, 33, "「白き翼」こと、ヴァイスフリューゲル…\nその名に恥じぬよう、天高く舞い、\n華麗に敵を倒してみせる！", 7, 28);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (149, "剣術、年長者をからかう", "A", 114301, "トモ（マジカル）", "ヒューマン", 8, "義理堅くてからかい好きな剣術少女", 13, "王宮騎士団（NIGHTMARE）", "茅原実里", 0, 43, "", 8, 11);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (157, "慈善事業", "AB", 114401, "アキノ（クリスマス）", "ヒューマン", 12, "一人前の商人を目指すパワフルお嬢様", 18, "メルクリウス財団", "松嵜麗", 0, 45, "この私とともにいる限り、\nお金に不自由はさせませんわ！", 3, 12);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (156, "経営、お茶会", "A", 114501, "サレン（クリスマス）", "エルフ", 9, "救護院を経営する優しい庶民派お嬢様", 17, "サレンディア救護院", "堀江由衣", 0, 43, "貧乏性？　いいえ、\n「もったいない」の精神で\n日々を過ごしてるだけよ！", 10, 4);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (164, "ウインドーショッピング", "A", 114601, "ユカリ（クリスマス）", "エルフ", 12, "純情でほっとけない大人の女性", 22, "メルクリウス財団", "今井麻美", 0, 55, "キミには情けないところばかり\n見られているけど、こんなところ、\nキミ以外には見せないんだからね？", 3, 16);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (148, "冒険、思い出話", "O", 114701, "ムイミ（ニューイヤー）", "ヒューマン", "", "さまよえる謎の少女", 16, "？？？", "潘めぐみ", 0, 40, "いいんだ、アタシは……独りでも。大丈夫だから、もう慣れたからさぁ", 8, 11);
