INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (140, "瞑想、動植物の飼育", "B", 115501, "コッコロ（儀装束）", "エルフ", 1, "主を慕う、小さなガイド役", 11, "美食殿", "伊藤美来", 0, 35, "主さまのガイド役を仰せつかりました\nわたくし、主さまに満足していただけるよう\n誠心誠意尽くさせていただきます", 5, 11);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (158, "料理、人間観察", "O", 115601, "ユイ（儀装束）", "ヒューマン", 2, "戦闘のサポートが得意な、心優しい少女", 17, "トゥインクルウィッシュ", "種田梨沙", 0, 47, "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！", 4, 5);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (152, "読書、推理", "AB", 115701, "カスミ（サマー）", "獣人族", 10, "頭脳明晰な美少女名探偵", 15, "自警団（カォン）", "水瀬いのり", 0, 41, "", 11, 3);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (150, "毛繕い、お喋り", "A", 115801, "リマ（シンデレラ）", "獣人族", 11, "乙女チックなもふもふアニマル", 17, "牧場（エリザベスパーク）", "徳井青空", 0, 100, "私、ごく普通の、どこにでもいる女の子よ！\nみ、見た目以外はね…", 3, 14);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (168, "お菓子作り", "O", 115901, "マコト（シンデレラ）", "獣人族", 10, "男勝りで情に厚いワイルド娘", 17, "自警団（カォン）", "小松未可子", 0, 54, "腹へってたら言えよな\n簡単でよければ\nすっげー旨いもん食わせてやるよ！", 8, 9);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (155, "空想、ぬいぐるみ集め", "O", 116001, "マホ（シンデレラ）", "獣人族", 10, "マホマホ王国のプリンセス", 16, "自警団（カォン）", "内田真礼", 0, 42, "マホマホ王国のお姫はんの、マホ姫どす！\nけったいな顔してどないしはったん？\nマホマホ王国はずーっと遠くの国なんどす？", 9, 22);
