INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (158, "猫とたわむれること", "AB", 116801, "タマキ（作業服）", "獣人族", 12, "弱きを助け強きをくじく猫娘", 19, "メルクリウス財団", "沼倉愛美", 0, 48, "お金もうけの話なら、ぜひともあたしに\n持ってくるにゃ！　稼げるなら１ルピだって\n見逃さないのが、あたしの信条にゃ～♪", 3, 1);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (163, "傭兵などのアルバイト", "O", 116901, "ミフユ（作業服）", "ヒューマン", 12, "仕事も私事も効率優先な傭兵少女", 20, "メルクリウス財団", "田所あずさ", 0, 49, "私がキミの師匠になってあげる！\nもちろんタダとはいかないわ\n時給はしっかりもらうから", 11, 11);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (154, "実験、裁縫、料理", "B", 117001, "エリコ（サマー）", "魔族", 13, "運命の相手に一途すぎる乙女", 16, "トワイライトキャラバン", "橋本ちなみ", 0, 43, "『壊し屋』の二つ名を持つ私…\nですが、怖がる必要はありませんわ\nあなた様は大切な運命の人ですから…", 7, 30);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (168, "家事全般", "O", 117101, "シズル（サマー）", "ヒューマン", 3, "お姉ちゃんがお世話してあげるからねっ！", 18, "ラビリンス", "生天目仁美", 0, 54, "身の回りのお世話はお姉ちゃんがやってあげるね！\nお料理も、お洗濯も、お掃除も\nお風呂で背中も流してあげちゃうぞっ！", 10, 24);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (157, "舞台鑑賞、ダンス", "B", 117201, "ノゾミ（サマー）", "ヒューマン", 4, "歌って踊れる大人気アイドル", 17, "カルミナ", "日笠陽子", 0, 40, "", 1, 24);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (163, "各種楽器", "O", 117301, "チカ（サマー）", "ヒューマン", 4, "人々を守るために歌う、唱喚士の少女", 17, "カルミナ", "福原綾香", 0, 46, "私は人々の平和を守るため、唱喚術を使って\n戦います。…最近は、ア、アイドルとしても\n活動してますが、そちらはまだ不慣れで…", 6, 3);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (153, "裁縫", "AB", 117401, "ツムギ（サマー）", "ヒューマン", 4, "ファッション大好きなキュートガール", 14, "カルミナ", "木戸衣吹", 0, 45, "", 9, 7);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (166, "研究、実験", "A", 117501, "ミツキ（オーエド）", "ヒューマン", 13, "実験が趣味の危険な科学者", 27, "トワイライトキャラバン", "三石琴乃", 0, 53, "私は科学者だけど、\n医者の真似事もしてるの\n病気になったら診てあげるわ", 3, 7);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (150, "鏡で自分を見ること", "AB", 117601, "ユキ（オーエド）", "エルフ", 15, "ボクは誰よりも美しい", 14, "ヴァイスフリューゲル　ランドソル支部", "大空直美", 0, 40, "ボクって本当に美しいなあ…\n可愛くて美しいなんて本当に罪だと思うけど\n生まれもったものだから仕方ないんだ♪", 10, 10);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (158, "踊り、空手", "A", 117701, "カオリ（ハロウィン）", "獣人族", 10, "いつでも「なんくるないさ～」な天然娘", 17, "自警団（カォン）", "高森奈津美", 0, 53, "ハイターイ！　歌って踊って、\n最高に盛り上がるさ～！\nやさやさ、キミも一緒に踊るさ～！", 7, 7);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (163, "忍法開発", "O", 117801, "ニノン（ハロウィン）", "ヒューマン", 15, "トーゴクの神秘、オシエテクダサイ！", 16, "ヴァイスフリューゲル　ランドソル支部", "佐藤聡美", 0, 51, "スシ、ゲイシャ、テンプラ…\nはふぅ～！\nトーゴクの文化はステキデスね～！", 8, 31);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (167, "ファッション", "O", 117901, "スズナ（ハロウィン）", "魔族", 14, "天真爛漫で人気者のカリスマモデル", 17, "ルーセント学院", "上坂すみれ", 0, 48, "ヒデサイ、ちょっす～！　うち、漢字と計算は\nちょっち…てか、おに苦手なんだ～\nでもでも、ファッションだったら任せて～！", 4, 10);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (160, "お金を数えること、悪だくみ", "A", 118001, "クレジッタ", "ヒューマン", 18, "忠義に目覚めた女商人", 26, "リッチモンド商工会", "Lynn", 0, 57, "", 9, 19);
