INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (162, "恋愛小説、恋愛舞台、恋愛漫画の鑑賞", "B", 119001, "イオ（ノワール）", "魔族", 14, "多くの男性を魅了する無垢な女教師", 23, "ルーセント学院", "伊藤静", 0, 52, "いつも助けてくれてありがとう\n私のほうが年上なのに\n頼ってばかりでごめんなさい～", 8, 14);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (157, "小説を読むこと", "AB", 119101, "クウカ（ノワール）", "ヒューマン", 15, "妄想大好き！　ほんとは照れ屋な女の子", 18, "ヴァイスフリューゲル　ランドソル支部", "長妻樹里", 0, 49, "あなたのことを考えていました\n…逆らえないクウカをああして、こうして\nぐふ、ぐふふふ…", 11, 19);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (142, "漫才", "B", 119201, "マヒル（クリスマス）", "ヒューマン", 11, "みんなを笑顔にするお笑い牧場主", 20, "牧場（エリザベスパーク）", "新田恵海", 0, 35, "オラはどんな時でもみんなに笑顔を届ける\n最高の芸人目指してる！\n一緒に頑張るべ！", 3, 3);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (156, "お裁縫", "A", 119301, "リノ（クリスマス）", "ヒューマン", 3, "人懐っこくてマシンガントークな妹系少女", 15, "ラビリンス", "阿澄佳奈", 0, 44, "覚えていないと思うんですけど…\n私は妹なんですよ！\nだからお兄ちゃんって呼んでいいですか？", 8, 25);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (130, "プリンを食べること", "B", 119901, "ミヤコ（クリスマス）", "魔族", 7, "プリン大好きゴースト娘", 14, "悪魔偽王国軍（ディアボロス）", "雨宮天", 0, 32, "難しいことはわからないの～\nただ毎日プリンを食べられるなら、\n幽霊のままでいいの～", 1, 23);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (168, "家事全般", "O", 120001, "シズル（ノワール）", "ヒューマン", 3, "お姉ちゃんがお世話してあげるからねっ！", 18, "ラビリンス", "生天目仁美", 0, 54, "身の回りのお世話はお姉ちゃんがやってあげるね！\nお料理も、お洗濯も、お掃除も\nお風呂で背中も流してあげちゃうぞっ！", 10, 24);
