INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (152, "猫と遊ぶ", "A", 121101, "キャル（オーバーロード）", "獣人族", 1, "行き倒れの謎のネコミミ魔法使い", 14, "美食殿", "立花理香", 0, 39, "", 9, 2);
