INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (150, "観劇、おままごと", "B", 121301, "クルミ（ステージ）", "ヒューマン", 9, "泣き虫で臆病な守ってあげたい女の子", 12, "サレンディア救護院", "植田佳奈", 0, 40, "あの、えっと…私、く、クルミですぅ…\nふ、ふぇぇぇ…ど、どうしようぅ…\nは、恥かしくて…ご、ごめんなさいぃぃ！", 6, 9);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (120, "ファッション誌鑑賞、コスメ集め", "A", 121401, "ミサキ（ステージ）", "魔族", 14, "ちょっとおませな恋に恋する女の子", 11, "ルーセント学院", "久野美咲", 0, 22, "アタシのこと呼んだ？\nレディの魅力で夢中にさせてあげるわね！", 1, 3);
