INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (159, "小説執筆", "A", 121901, "アンナ（パイレーツ）", "魔族", 13, "前世を信じる中二病患者、「疾風の冥姫」", 17, "トワイライトキャラバン", "髙野麻美", 0, 45, "いいか、絶対に私を真名で呼ぶなよ？\n常に「機関」の眼や耳の存在を疑え\nそれが、生きのびるための術だ…！", 7, 5);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (157, "占い", "AB", 122001, "シノブ（パイレーツ）", "魔族", 7, "占いが得意な霊能少女", 18, "悪魔偽王国軍（ディアボロス）", "大坪由佳", 0, 42, "私、小さい頃から人には見えないものが\n見えていたんです。今もあなたの後ろに\n一人、二人、三人…賑やかですね", 12, 22);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (158, "友達作りのイメトレ", "AB", 122101, "アオイ（キャンプ）", "エルフ", 6, "「友達」に憧れる、エルフの森の女の子", 13, "フォレスティエ", "花澤香菜", 0, 44, "", 6, 6);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (164, "ウインドーショッピング", "A", 122201, "ユカリ（キャンプ）", "エルフ", 12, "純情でほっとけない大人の女性", 22, "メルクリウス財団", "今井麻美", 0, 55, "キミには情けないところばかり\n見られているけど、こんなところ、\nキミ以外には見せないんだからね？", 3, 16);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (149, "お散歩、お料理", "AB", 122301, "ヴァンピィ", "魔族", "", "けんぞくのご主人様", "??", "？？？", "釘宮理恵", 0, 41, "", 12, 6);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (155, "人助け、応援", "A", 122401, "ヒヨリ（サマー）", "獣人族", 2, "人助けが大好き！　前向き格闘娘", 16, "トゥインクルウィッシュ", "東山奈央", 0, 44, "こんにちは！　ヒヨリでっす！\n困っている人がいたら助けにいくよ！\nよかったら一緒に来ない？", 8, 27);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (163, "読書、乗馬、お茶", "B", 122501, "レイ（サマー）", "魔族", 2, "クールで何事にも真っ直ぐな剣士", 18, "トゥインクルウィッシュ", "早見沙織", 0, 46, "キミと会ったのもきっと何かの縁だ\n一緒に塔の頂上を目指す仲間として\n頑張っていこう。よろしく頼む", 1, 12);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (158, "料理、人間観察", "O", 122601, "ユイ（サマー）", "ヒューマン", 2, "戦闘のサポートが得意な、心優しい少女", 17, "トゥインクルウィッシュ", "種田梨沙", 0, 47, "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！", 4, 5);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (118, "お勉強", "A", 122701, "キョウカ（サマー）", "エルフ", 5, "礼儀正しくしっかり者のちびっ子優等生", 8, "リトルリリカル", "小倉唯", 0, 21, "", 2, 2);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (128, "いたずら、探検", "O", 122801, "ミソギ（サマー）", "ヒューマン", 5, "探検好きのイタズラっ子", 9, "リトルリリカル", "諸星すみれ", 0, 27, "イタズラなら任せて！\nにいちゃん、引っかからないように気を付けなよー♪", 8, 10);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (117, "かわいいもの集め", "O", 122901, "ミミ（サマー）", "獣人族", 5, "お歌もにんじんも、ウサギさんも大好き♪", 10, "リトルリリカル", "日高里菜", 0, 21, "ぴょんぴょん、うさぎさんになりたいな～♪　\nミミ、うさぎさんになれたら、\n最初におにいちゃんに見せてあげるね！", 4, 3);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (150, "？？？", "?", 123001, "アメス", "？？？", "", "新たな姿で騎士の冒険を支え続ける妖精", "??", "？？？", "相坂優歌", 0, "???", "", "?", "?");
