INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (158, "猫とたわむれること", "AB", 125101, "タマキ（カフェ）", "獣人族", 12, "弱きを助け強きをくじく猫娘", 19, "メルクリウス財団", "沼倉愛美", 0, 48, "お金もうけの話なら、ぜひともあたしに\n持ってくるにゃ！　稼げるなら１ルピだって\n見逃さないのが、あたしの信条にゃ～♪", 3, 1);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (140, "お菓子屋通い", "A", 125201, "モニカ（カフェ）", "ヒューマン", 15, "見た目も中身もお子ちゃまな異国の軍人", 17, "ヴァイスフリューゲル　ランドソル支部", "辻あゆみ", 0, 33, "「白き翼」こと、ヴァイスフリューゲル…\nその名に恥じぬよう、天高く舞い、\n華麗に敵を倒してみせる！", 7, 28);
