INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (165, "歌、読書、詩を書くこと", "O", 126901, "ランファ（サマー）", "魔族", 19, "静寂を求め歌う陰気少女", 20, "レイジ・レギオン", "原田彩楓", 0, 53, "", 12, 28);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (157, "小説を読むこと", "AB", 127001, "クウカ（サマー）", "ヒューマン", 15, "妄想大好き！　ほんとは照れ屋な女の子", 18, "ヴァイスフリューゲル　ランドソル支部", "長妻樹里", 0, 49, "あなたのことを考えていました\n…逆らえないクウカをああして、こうして\nぐふ、ぐふふふ…", 11, 19);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (157, "占い", "AB", 127101, "シノブ（サマー）", "魔族", 7, "占いが得意な霊能少女", 18, "悪魔偽王国軍（ディアボロス）", "大坪由佳", 0, 42, "私、小さい頃から人には見えないものが\n見えていたんです。今もあなたの後ろに\n一人、二人、三人…賑やかですね", 12, 22);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (152, "猫と遊ぶ", "A", 127201, "キャル（編入生）", "獣人族", 1, "行き倒れの謎のネコミミ魔法使い", 14, "美食殿", "立花理香", 0, 39, "なに、モタモタしてんのよ\n仕方ないから、あたしが手伝ってあげるわ\nいい？　感謝しなさいよね！", 9, 2);
