INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (156, "経営、お茶会", "A", 127501, "サレン（サラサリア）", "エルフ", 9, "救護院を経営する優しい庶民派お嬢様", 17, "サレンディア救護院", "堀江由衣", 0, 43, "貧乏性？　いいえ、\n「もったいない」の精神で\n日々を過ごしてるだけよ！", 10, 4);
