INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (155, "人助け、応援", "A", 128701, "ヒヨリ（アストラル）", "獣人族", 2, "人助けが大好き！　前向き格闘娘", 16, "トゥインクルウィッシュ", "東山奈央", 0, 44, "こんにちは！　ヒヨリでっす！\n困っている人がいたら助けにいくよ！\nよかったら一緒に来ない？", 8, 27);
