INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (158, "料理、人間観察", "O", 136401, "ユイ（クリスマス）", "ヒューマン", 2, "戦闘のサポートが得意な、心優しい少女", 17, "トゥインクルウィッシュ", "種田梨沙", 0, 47, "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！", 4, 5);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (168, "家事全般", "O", 136501, "シズル（ニューイヤー）", "ヒューマン", 3, "お姉ちゃんがお世話してあげるからねっ！", 18, "ラビリンス", "生天目仁美", 0, 54, "身の回りのお世話はお姉ちゃんがやってあげるね！\nお料理も、お洗濯も、お掃除も\nお風呂で背中も流してあげちゃうぞっ！", 10, 24);
