INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (155, "人助け、応援", "A", 180101, "ヒヨリ（プリンセス）", "獣人族", 2, "人助けが大好き！　前向き格闘娘", 16, "トゥインクルウィッシュ", "東山奈央", 0, 44, "こんにちは！　ヒヨリでっす！\n困っている人がいたら助けにいくよ！\nよかったら一緒に来ない？", 8, 27);
INSERT INTO `v1_fe48ab555c90adeee85897d2ad44b70d9c27199a934a34af69aac507cb5e9d01` VALUES (158, "料理、人間観察", "O", 180201, "ユイ（プリンセス）", "ヒューマン", 2, "戦闘のサポートが得意な、心優しい少女", 17, "トゥインクルウィッシュ", "種田梨沙", 0, 47, "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！", 4, 5);
